import { useState } from "react";
import styles from "./AuctionAside.module.scss";

export default function AuctionAside({
  title = "Tipos",
  options = ["Todos", "Seguradora", "Banco", "Particular"],
  defaultSelected = "Todos",
  onSelect = () => {},
}){
  const [selected, setSelected] = useState(defaultSelected);

  const handleSelect = (option) => {
    setSelected(option);
    onSelect(option);
  };

  return (
    <>
      <div className={styles.fs_wrap}>
        <div className={styles.fs_header}>
          <div className={styles.fs_icon}>
            <span /><span /><span /><span />
          </div>
          <span className={styles.fs_title}>{title}</span>
        </div>

        {options.map((opt) => (
          <button
            key={opt}
            className={`fs-btn${selected === opt ? " active" : ""}`}
            onClick={() => handleSelect(opt)}
          >
            {opt}
          </button>
        ))}
      </div>
    </>
  );
};
